import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine(); // Use nextLine() to read entire input line

        int maxLength = 10; // Set maximum buffer length
        char[] buffer = new char[maxLength];

        int inputLength = Math.min(input.length(), maxLength); // Limit input length to buffer size

        for (int i = 0; i < inputLength; i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

